+/// Format wait time in seconds to a human-readable string.
+fn format_wait_time(secs: u64) -> String {
+    if secs < 60 {
+        format!("{}s", secs)
+    } else if secs < 3600 {
+        let mins = secs / 60;
+        let s = secs % 60;
+        if s == 0 {
+            format!("{}m", mins)
+        } else {
+            format!("{}m {}s", mins, s)
+        }
+    } else {
+        let hours = secs / 3600;
+        let mins = (secs % 3600) / 60;
+        if mins == 0 {
+            format!("{}h", hours)
+        } else {
+            format!("{}h {}m", hours, mins)
+        }
+    }
+}
